// 定义一个调度器类
class Scheduler:
    def __init__(self):
        self.task_queue = []  // 任务队列，用于存储所有待执行的任务
        self.running_tasks = {}  // 正在运行的任务字典，键为任务ID，值为任务对象
        self.task_priority = {}  // 任务优先级字典，键为任务ID，值为优先级数值

    // 添加任务到调度器
    def add_task(self, task_id, task_function, priority=1):
        task = {
            'id': task_id,
            'function': task_function,
            'priority': priority,
            'status': 'PENDING'  // 任务状态：PENDING（待执行）、RUNNING（运行中）、FINISHED（已完成）
        }
        self.task_queue.append(task)
        self.task_priority[task_id] = priority

    // 从任务队列中移除并执行具有最高优先级的任务
    def run_next_task(self):
        if not self.task_queue:
            return  // 如果任务队列为空，则不执行任何操作

        # 找到优先级最高的任务
        highest_priority_task = max(self.task_queue, key=lambda x: x['priority'])

        # 将任务从队列中移除并标记为正在运行
        task = self.task_queue.pop(self.task_queue.index(highest_priority_task))
        task['status'] = 'RUNNING'
        self.running_tasks[task['id']] = task

        # 执行任务
        try:
            task['function']()
        except Exception as e:
            print(f"Error running task {task['id']}: {e}")

        # 任务执行完毕，从正在运行的任务字典中移除
        del self.running_tasks[task['id']]
